package com.promonts.dto;import com.promonts.domain.course.Course;import lombok.*;import java.time.LocalDateTime;@Data @NoArgsConstructor @AllArgsConstructor @Builder public class CourseResponse{private Long id;private String name;private String code;private ProfessorInfo professor;private String semester;private Integer year;private String description;private LocalDateTime createdAt;@Data @AllArgsConstructor public static class ProfessorInfo{private Long id;private String name;private String email;}public static CourseResponse from(Course course){ProfessorInfo professorInfo=new ProfessorInfo(course.getProfessor().getId(),course.getProfessor().getName(),course.getProfessor().getEmail());return CourseResponse.builder().id(course.getId()).name(course.getName()).code(course.getCode()).professor(professorInfo).semester(course.getSemester()).year(course.getYear()).description(course.getDescription()).createdAt(course.getCreatedAt()).build();}}
